# Taken from Pydantic v1 as is
def isoformat(o: Union[datetime.date, datetime.time]) -> str:
    """Return an ISO 8601 string representation for a date or time object.

    This wrapper exists for consistency with pydantic's encoders and to allow
    overriding or customization if needed.
    """
    return o.isoformat()


# Taken from Pydantic v1 as is
# TODO: pv2 should this return strings instead?
def decimal_encoder(dec_value: Decimal) -> Union[int, float]:
    """
    Encodes a Decimal as int of there's no exponent, otherwise float

    This is useful when we use ConstrainedDecimal to represent Numeric(x,0)
    where a integer (but not int typed) is used. Encoding this as a float
    results in failed round-tripping between encode and parse.
    Our Id type is a prime example of this.

    >>> decimal_encoder(Decimal("1.0"))
    1.0

    >>> decimal_encoder(Decimal("1"))
    1
    """
    if dec_value.as_tuple().exponent >= 0:  # type: ignore[operator]
        return int(dec_value)
    else:
        return float(dec_value)


ENCODERS_BY_TYPE: Dict[Type[Any], Callable[[Any], Any]] = {
    bytes: lambda o: o.decode(),
    Color: str,
    datetime.date: isoformat,
    datetime.datetime: isoformat,
    datetime.time: isoformat,
    datetime.timedelta: lambda td: td.total_seconds(),
    Decimal: decimal_encoder,
    Enum: lambda o: o.value,
    frozenset: list,
    deque: list,
    GeneratorType: list,
    IPv4Address: str,
    IPv4Interface: str,
    IPv4Network: str,
    IPv6Address: str,
    IPv6Interface: str,
    IPv6Network: str,
    NameEmail: str,
    Path: str,
    Pattern: lambda o: o.pattern,
    SecretBytes: str,
    SecretStr: str,
    set: list,
    UUID: str,
    Url: str,
    AnyUrl: str,
}


def generate_encoders_by_class_tuples(
    type_encoder_map: Dict[Any, Callable[[Any], Any]]
) -> Dict[Callable[[Any], Any], Tuple[Any, ...]]:
    """Invert a mapping of types to encoder functions into a mapping of encoder
    functions to a tuple of types they handle.

    This is useful for grouping types by the encoder used for them.
    """
    encoders_by_class_tuples: Dict[Callable[[Any], Any], Tuple[Any, ...]] = defaultdict(
        tuple
    )
    for type_, encoder in type_encoder_map.items():
        encoders_by_class_tuples[encoder] += (type_,)
    return encoders_by_class_tuples


encoders_by_class_tuples = generate_encoders_by_class_tuples(ENCODERS_BY_TYPE)


def jsonable_encoder(
    obj: Annotated[
        Any,
        Doc(
            """
            The input object to convert to JSON.
            """
        ),
    ],
    include: Annotated[
        Optional[IncEx],
        Doc(
            """
            Pydantic's `include` parameter, passed to Pydantic models to set the
            fields to include.
            """
        ),
    ] = None,
    exclude: Annotated[
        Optional[IncEx],
        Doc(
            """
            Pydantic's `exclude` parameter, passed to Pydantic models to set the
            fields to exclude.
            """
        ),
    ] = None,
    by_alias: Annotated[
        bool,
        Doc(
            """
            Pydantic's `by_alias` parameter, passed to Pydantic models to define if
            the output should use the alias names (when provided) or the Python
            attribute names. In an API, if you set an alias, it's probably because you
            want to use it in the result, so you probably want to leave this set to
            `True`.
            """
        ),
    ] = True,
    exclude_unset: Annotated[
        bool,
        Doc(
            """
            Pydantic's `exclude_unset` parameter, passed to Pydantic models to exclude
            fields that were not set (useful for PATCH operations).
            """
        ),
    ] = False,
    exclude_defaults: Annotated[
        bool,
        Doc(
            """
            Pydantic's `exclude_defaults` parameter, passed to Pydantic models to exclude
            fields that are equal to their default values.
            """
        ),
    ] = False,
    exclude_none: Annotated[
        bool,
        Doc(
            """
            If True, fields that are None will be excluded from the output.
            """
        ),
    ] = False,
    include_none: Annotated[
        bool,
        Doc(
            """
            If True, fields that are None will be included in the output.
            """
        ),
    ] = False,
    custom_encoder: Annotated[
        Optional[Dict[Any, Callable[[Any], Any]]],
        Doc(
            """
            A mapping of types to callables that will be used to encode objects
            of those types.
            """
        ),
    ] = None,
    sqlalchemy_safe: Annotated[
        bool,
        Doc(
            """
            If True, handle SQLAlchemy row and column types safely.
            """
        ),
    ] = False,
    namedtuple_as_dict: Annotated[
        bool,
        Doc(
            """
            If True, convert namedtuples to dicts.
            """
        ),
    ] = True,
    datetime_format: Annotated[
        Optional[str],
        Doc(
            """
            Optional format string to format datetimes via strftime.
            """
        ),
    ] = None,
):
    if dataclasses.is_dataclass(obj) and not isinstance(obj, type):
        return dataclasses.asdict(obj)

    if isinstance(obj, BaseModel):
        if PYDANTIC_V2:
            return _model_dump(obj, include=include, exclude=exclude, by_alias=by_alias)
        else:
            return obj.dict(
                include=include,
                exclude=exclude,
                by_alias=by_alias,
                exclude_unset=exclude_unset,
                exclude_defaults=exclude_defaults,
                exclude_none=exclude_none,
            )

    if isinstance(obj, (str, bytes, int, float, bool)) or obj is None:
        return obj

    if isinstance(obj, (list, set, frozenset, deque, GeneratorType)):
        return [jsonable_encoder(v, include, exclude, by_alias) for v in obj]

    if isinstance(obj, dict):
        encoded_dict = {}
        for k, v in obj.items():
            if include is not None and k not in include:  # type: ignore[arg-type]
                continue
            if exclude is not None and k in exclude:  # type: ignore[arg-type]
                continue
            encoded_key = k if isinstance(k, str) else str(k)
            encoded_dict[encoded_key] = jsonable_encoder(v, include, exclude, by_alias)
        return encoded_dict

    # handle Path and PurePath
    if isinstance(obj, (Path, PurePath)):
        return str(obj)

    # custom encoders
    if custom_encoder:
        for type_, encoder in custom_encoder.items():
            if isinstance(obj, type_):
                return encoder(obj)

    # encoders by type
    for type_, encoder in ENCODERS_BY_TYPE.items():
        if isinstance(obj, type_):
            return encoder(obj)

    # encoders by class tuples
    for encoder, types_tuple in encoders_by_class_tuples.items():
        if isinstance(obj, types_tuple):
            return encoder(obj)

    # Fallback: dataclass-like objects with __dict__
    if hasattr(obj, "__dict__"):
        data = {}
        for k, v in obj.__dict__.items():
            if not k.startswith("_"):
                data[k] = jsonable_encoder(v, include, exclude, by_alias)
        return data

    # Fallback: try to convert to string
    return str(obj)